export interface Case {
  id: number;
  name: string;
  price_stars: number;
  image_url: string;
  category: 'basic' | 'premium' | 'exclusive' | 'game_specific';
  game?: string; // например 'CS:GO', 'Dota 2', 'Rust'
}

export const casesData: Case[] = [
  // Базовые (до 50 ⭐)
  { id: 1, name: 'Стартовый набор', price_stars: 25, image_url: '/images/cases/start.png', category: 'basic' },
  { id: 2, name: 'Удача новичка', price_stars: 40, image_url: '/images/cases/luck.png', category: 'basic' },
  { id: 3, name: 'Кейс CS:GO Basic', price_stars: 50, image_url: '/images/cases/csgo_basic.png', category: 'game_specific', game: 'CS:GO' },

  // Средние (50-150 ⭐)
  { id: 4, name: 'Оружейный арсенал', price_stars: 75, image_url: '/images/cases/arsenal.png', category: 'premium' },
  { id: 5, name: 'Dota 2 Сундук', price_stars: 90, image_url: '/images/cases/dota_treasure.png', category: 'game_specific', game: 'Dota 2' },
  { id: 6, name: 'Редкие скины', price_stars: 120, image_url: '/images/cases/rare.png', category: 'premium' },
  { id: 7, name: 'Rust Ящик', price_stars: 140, image_url: '/images/cases/rust_crate.png', category: 'game_specific', game: 'Rust' },
  { id: 8, name: 'Киберпанк 2077', price_stars: 150, image_url: '/images/cases/cyber.png', category: 'exclusive' },

  // Дорогие (150-250 ⭐)
  { id: 9, name: 'Легендарное оружие', price_stars: 180, image_url: '/images/cases/legendary.png', category: 'exclusive' },
  { id: 10, name: 'Ножи и перчатки', price_stars: 220, image_url: '/images/cases/knives.png', category: 'exclusive', game: 'CS:GO' },
  { id: 11, name: 'Аркана Dota 2', price_stars: 250, image_url: '/images/cases/arcana.png', category: 'game_specific', game: 'Dota 2' },
  { id: 12, name: 'Редкие вещи Rust', price_stars: 200, image_url: '/images/cases/rust_rare.png', category: 'game_specific', game: 'Rust' },
  { id: 13, name: 'Кейс с гарантией', price_stars: 250, image_url: '/images/cases/guaranteed.png', category: 'premium' },
  { id: 14, name: 'Эпический набор', price_stars: 190, image_url: '/images/cases/epic.png', category: 'exclusive' },
  { id: 15, name: 'Золотой билет', price_stars: 150, image_url: '/images/cases/golden.png', category: 'basic' },
];
